// src/pages/Login.js
import React, { useState } from 'react';
import { useApp } from '../context/AppContext';
import './Login.css';
<img src="/logo.png" alt="College Logo" width={60} height={60} />


// Demo credentials
const ADMIN_CREDENTIALS = { username: 'admin', password: 'admin123' };

export default function Login({ setActivePage }) {
  const { setCurrentUser, staff } = useApp();
  const [loginType, setLoginType] = useState('staff'); // 'staff' | 'admin'
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError]       = useState('');
  const [loading, setLoading]   = useState(false);
  const [showPass, setShowPass] = useState(false);

  const handleLogin = (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    setTimeout(() => {
      if (loginType === 'admin') {
        if (username === ADMIN_CREDENTIALS.username && password === ADMIN_CREDENTIALS.password) {
          setCurrentUser({ id: 0, name: 'Admin', role: 'admin' });
          setActivePage('Dashboard');
        } else {
          setError('Invalid admin credentials. Try admin / admin123');
        }
      } else {
        // Staff login — match by name (case-insensitive) or id
        const found = staff.find(
          s => s.name.toLowerCase().replace(/\s+/g, '') === username.toLowerCase().replace(/\s+/g, '')
            || String(s.id) === username
        );
        if (found && password === 'staff123') {
          setCurrentUser({ id: found.id, name: found.name, role: 'teacher' });
          setActivePage('Dashboard');
        } else {
          setError('Invalid credentials. Use your name (or staff ID) and password: staff123');
        }
      }
      setLoading(false);
    }, 700);
  };

  return (
    <div className="login-root">
      {/* Left panel */}
      <div className="login-left">
        <div className="login-left-content">
          <CollegeLogo />
          <h1 className="login-college">SSVPSS Bapusaheb<br />Shivajirao Deore<br />Polytechnic</h1>
          <div className="login-divider" />
          <p className="login-tagline">Faculty Leave Management System</p>
          <ul className="login-perks">
            <li>📋 Apply &amp; track leave online</li>
            <li>🔄 Auto substitute assignment</li>
            <li>✅ Fast admin approvals</li>
            <li>🔔 Real-time notifications</li>
          </ul>
        </div>
      </div>

      {/* Right panel */}
      <div className="login-right">
        <div className="login-card">

          {/* Toggle */}
          <div className="login-toggle">
            <button
              className={`login-toggle-btn ${loginType === 'staff' ? 'active' : ''}`}
              onClick={() => { setLoginType('staff'); setError(''); setUsername(''); setPassword(''); }}
            >
              👨‍🏫 Staff Login
            </button>
            <button
              className={`login-toggle-btn ${loginType === 'admin' ? 'active' : ''}`}
              onClick={() => { setLoginType('admin'); setError(''); setUsername(''); setPassword(''); }}
            >
              🔐 Admin Login
            </button>
          </div>

          <h2 className="login-title">
            {loginType === 'admin' ? 'Administrator Portal' : 'Staff Portal'}
          </h2>
          <p className="login-subtitle">
            {loginType === 'admin'
              ? 'Sign in to manage leave requests and staff'
              : 'Sign in to apply and track your leaves'}
          </p>

          <form onSubmit={handleLogin} className="login-form">
            <div className="login-field">
              <label>{loginType === 'admin' ? 'Username' : 'Name / Staff ID'}</label>
              <input
                type="text"
                placeholder={loginType === 'admin' ? 'Enter username' : 'Enter your name or staff ID'}
                value={username}
                onChange={e => setUsername(e.target.value)}
                required
                autoComplete="username"
              />
            </div>

            <div className="login-field">
              <label>Password</label>
              <div className="login-pass-wrap">
                <input
                  type={showPass ? 'text' : 'password'}
                  placeholder="Enter password"
                  value={password}
                  onChange={e => setPassword(e.target.value)}
                  required
                  autoComplete="current-password"
                />
                <button type="button" className="login-eye" onClick={() => setShowPass(p => !p)}>
                  {showPass ? '🙈' : '👁️'}
                </button>
              </div>
            </div>

            {error && <div className="login-error">⚠️ {error}</div>}

            <button type="submit" className="login-submit" disabled={loading}>
              {loading ? <span className="login-spinner" /> : (loginType === 'admin' ? 'Login as Admin' : 'Login as Staff')}
            </button>
          </form>

          <div className="login-hint">
            {loginType === 'admin'
              ? <><strong>Demo:</strong> username: <code>admin</code> &nbsp;|&nbsp; password: <code>admin123</code></>
              : <><strong>Demo:</strong> Use your name &amp; password: <code>staff123</code></>
            }
          </div>
        </div>
      </div>
    </div>
  );
}
